// แหล่งที่มาของ message
var field  = metadata.calculatedFieldName;


// ---------------- DISTANCE ----------------
if (field === "displayDistance") {

    var distance = msg.distanceOffset != null ? parseFloat(msg.distanceOffset) : null;
    var lowD  = msg.shared_LowDistanceAlarms  != null ? parseFloat(msg.shared_LowDistanceAlarms)  : null;
    var highD = msg.shared_HighDistanceAlarms != null ? parseFloat(msg.shared_HighDistanceAlarms) : null;

    msg.distanceLow  = (distance != null && lowD  != null && distance < lowD);
    msg.distanceHigh = (distance != null && highD != null && distance > highD);

    return { msg: msg, metadata: metadata, msgType: msgType };
}


// ---------------- SENSOR (ทุก node) ----------------

var battery = msg.battery != null ? parseFloat(msg.battery) : null;
var hum     = msg.humidity != null ? parseFloat(msg.humidity) : null;
var temp    = msg.temperature != null ? parseFloat(msg.temperature) : null;

var lowBatt = msg.shared_BatteryAlarms != null ? parseFloat(msg.shared_BatteryAlarms) : null;
var highHum = msg.shared_HumAlarms  != null ? parseFloat(msg.shared_HumAlarms)  : null;
var highTemp= msg.shared_TempAlarms != null ? parseFloat(msg.shared_TempAlarms) : null;

var enBat  = msg.shared_BatteryAlarmsEnable === true;
var enHum  = msg.shared_HumAlarmsEnable === true;
var enTemp = msg.shared_TempAlarmsEnable === true;

msg.batteryLow = (enBat && battery != null && battery < lowBatt);
msg.humHigh    = (enHum && hum != null && hum > highHum);
msg.tempHigh   = (enTemp && temp != null && temp > highTemp);

return { msg: msg, metadata: metadata, msgType: msgType };

